def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    primes_cache = {}
    def is_prime(n):
        if n < 2:
            return False
        if n in primes_cache:
            return primes_cache[n]
        for x in range(2, int(n**0.5) + 1):
            if n % x == 0:
                primes_cache[n] = False
                return False
        primes_cache[n] = True
        return True
    def collatz_steps(n):
        steps = 0
        while n > 1 and steps < 100:
            if n % 2 == 0:
                n = n // 2
            else:
                n = 3 * n + 1
            steps += 1
        return steps
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf if item > cap else 1000
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            for a in range(1, 10):
                decay = np.exp(-a*ratio*6)
                increment = decay * (25 / (a + 2)) * (np.cos(cap * a) + 1.5)
                score += increment
            prime_div = [p for p in range(2, int(cap//2)+1) if cap % p == 0 and is_prime(p)]
            for b in prime_div:
                score += (b ** 0.5) * 1.5
            if cap % 7 == 0:
                score *= 1.15
            cs = collatz_steps(int(cap))
            if cs < 20:
                score += (20 - cs) * 2.3
        elif 0.1 <= ratio < 0.35:
            base = np.tan(ratio * np.pi*3) * 10
            harmonic_sum = 0
            for c in range(1, 8):
                harmonic_sum += ((-1)**c) * np.sin(ratio * c * np.pi) / c
            score += base + harmonic_sum * 12
            divisible_vals = [5,8,10,12]
            div_found = False
            for d in divisible_vals:
                if cap % d == 0:
                    score += d * 1.3
                    div_found = True
            if div_found:
                score *= 1.05
            if cap % 17 == 0:
                score += 7
        elif 0.35 <= ratio < 0.6:
            sine_component = np.sin(ratio * np.pi * 7) * 20
            exp_component = 0
            for e in range(1,10):
                exp_component += ((-1)**e) * (ratio**e) / np.math.factorial(e)
            score += sine_component + exp_component * 15
            for g in range(3, int(min(15, cap))):
                if cap % g == 0 and g % 3 == 2:
                    score += np.cbrt(g) * 3
            if int(cap) % 4 == 0:
                score *= 1.12
        elif 0.6 <= ratio <= 0.9:
            logistic = 40 / (1 + np.exp(-40*(ratio - 0.75)))
            score += logistic
            for h in range(2,15):
                if is_prime(h) and h % 4 == 3:
                    score += h * 1.1
            if ratio > 0.85:
                score += (1 - ratio) * 90
            if cap % 6 == 0 and ratio < 0.9:
                score *= 1.18
            scoll = collatz_steps(int(cap))
            score += scoll * 0.8
        elif 0.9 < ratio <= 1.3:
            penalty = 0
            chunk = max(1, int(cap//4))
            for i in range(1, chunk+2):
                if cap % i == 0:
                    penalty += i ** 1.5
            fract = ratio - int(ratio)
            for j in range(1, 12):
                mod_val = (fract * j * 900) % 11
                penalty += (mod_val / 11) * 7
            score += penalty / (chunk + 3)
            score += (ratio - 1) * (-60)
            if cap % 19 == 0:
                score *= 0.85
            if int(cap) % 23 == 0:
                score += 22
        elif 1.3 < ratio < 2.0:
            complex_sum = 0
            for k in range(1, int(min(20, cap))):
                if cap % k == 0:
                    if k % 3 == 0:
                        complex_sum += np.log1p(k) * 4
                    else:
                        complex_sum += np.sqrt(k) * 3
            fract_part = ratio - int(ratio)
            for m in range(1,15):
                complex_sum += np.cos(fract_part * m * np.pi) * 2.5
            score += complex_sum
            score += (ratio - 1.5) * 80
            if ratio > 1.8:
                for n in range(1,int(cap//2)+1):
                    if n % 5 == 0:
                        score += np.sin(n) * 5
        else:
            mega_sum = 0
            for p in range(1, int(min(25, cap))):
                if cap % p == 0:
                    if p % 2 == 1:
                        mega_sum += np.log1p(p) * 5
                    else:
                        mega_sum += p ** 0.6 * 4
            fract_part2 = ratio - int(ratio)
            for q in range(1, 20):
                mega_sum += np.sin(fract_part2 * q * np.pi / 2) * 3
            score += mega_sum
            score += (ratio - 3) * 100
            if ratio > 5:
                for r in range(1, int(cap//4)+1):
                    if r % 6 == 0:
                        score += np.cos(r) * 6
            if int(cap) % 25 == 0:
                score *= 1.25
        if int(cap) % 7 == 0 and ratio < 2.2:
            score *= 1.1
        if int(cap) % 18 == 0 and ratio > 0.7:
            score *= 0.7
        if ratio > 4 and int(cap) % 15 == 0:
            score += 30
        if int(cap) % 21 == 0:
            score *= 0.78
        if int(cap) % 30 == 0 and ratio < 3.5:
            score *= 1.2
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 400)
    return priorities
